// Validar y extraer datos recibidos del webhook
const body = $input.item.json.body || $input.item.json;

// Validar campos obligatorios
if (!body.solicitud_id) {
  throw new Error('Falta solicitud_id en el request');
}

if (!body.auditado_email) {
  throw new Error('Falta auditado_email en el request');
}

if (!body.titulo || !body.descripcion) {
  throw new Error('Faltan titulo o descripcion en el request');
}

// Preparar datos para el correo
const data = {
  solicitud_id: body.solicitud_id,
  auditoria_id: body.auditoria_id || null,
  auditado_id: body.auditado_id || null,
  auditado_email: body.auditado_email,
  auditado_nombre: body.auditado_nombre || body.auditado_email.split('@')[0],
  titulo: body.titulo,
  descripcion: body.descripcion,
  tipo_documento: body.tipo_documento || null,
  fecha_limite: body.fecha_limite || null,
  solicitado_por_nombre: body.solicitado_por_nombre || 'Auditor',
  solicitado_por_email: body.solicitado_por_email || null,
  timestamp: body.timestamp || new Date().toISOString()
};

// Formatear fecha límite si existe
if (data.fecha_limite) {
  try {
    const fechaLimiteDate = new Date(data.fecha_limite);
    data.fecha_limite_formateada = fechaLimiteDate.toLocaleDateString('es-ES', {
      year: 'numeric',
      month: 'long',
      day: 'numeric'
    });
  } catch (e) {
    data.fecha_limite_formateada = data.fecha_limite;
  }
}

return [{
  json: {
    ...data,
    subject: `📋 Solicitud de Documentación - ${data.titulo}`
  }
}];

// Generar HTML del correo para el auditado
